export interface UserResponse {
  id: number;
  first_name: string;
  last_name: string;
  email: string;
  avatar_url: string;
}

export interface ApiResponse<T> {
  data: T;
  meta: { total: number; page: number };
}

export type UsersApiResponse = ApiResponse<UserResponse[]>;

