import { UserResponse, UsersApiResponse } from '../types';

export async function fetchUsers(): Promise<UserResponse[]> {
  const response = await fetch('/api/users');
  const json: UsersApiResponse = await response.json();
  return json.data;
}

export async function fetchUser(id: number): Promise<UserResponse> {
  const response = await fetch(`/api/users/${id}`);
  const json: { data: UserResponse } = await response.json();
  return json.data;
}

