import { UserResponse } from '../types';

export function toDisplayName(user: UserResponse): string {
  return `${user.first_name} ${user.last_name}`;
}

export function toUserMap(users: UserResponse[]): Map<number, UserResponse> {
  return new Map(users.map(u => [u.id, u]));
}

